"use client";

import { Radio, type RadioProps } from "./radio";
import {
  type RadioGroupActivationMode,
  type RadioGroupBoundaryDirection,
  type RadioGroupNavigationDirection,
  type RadioGroupProps,
  RadioGroup as RadioGroupRoot,
} from "./radio-group";
import { RadioGroupItem, type RadioGroupItemProps } from "./radio-group-item";

/** Group root with context, selection state, and keyboard navigation. */
const RadioGroup = Object.assign(RadioGroupRoot, {
  Item: RadioGroupItem,
});

export { Radio, type RadioProps };
export {
  RadioGroup,
  type RadioGroupActivationMode,
  type RadioGroupBoundaryDirection,
  type RadioGroupNavigationDirection,
  type RadioGroupProps,
};
export { RadioGroupItem, type RadioGroupItemProps };

"use client";

import {
  type AriaAttributes,
  Children,
  type ComponentPropsWithRef,
  isValidElement,
  type KeyboardEvent as ReactKeyboardEvent,
  type ReactNode,
  type Ref,
  useCallback,
  useEffect,
  useId,
  useMemo,
  useRef,
  useState,
} from "react";
import { useComposedRefs } from "@/hooks/use-composed-refs";
import { useControllableState } from "@/hooks/use-controllable-state";
import { mergeIds, resolveAriaInvalid } from "@/lib/aria";
import { useFieldsetDisabled } from "@/lib/fieldset-disabled";
import {
  getEnabledSelectableCollectionItems,
  resolveSelectableCollectionItem,
  useSelectableCollection,
} from "@/lib/selectable-collection";
import { type SelectableVariant, selectableLabelVariants } from "@/lib/selectable-variants";
import { cn } from "@/lib/utils";
import { warnUnregisteredValue } from "@/lib/warn-unregistered-value";
import type { RadioSize } from "./radio";
import { RadioGroupContext, type RadioGroupContextValue } from "./radio-group-context";
import { RadioGroupItem, type RadioGroupItemProps } from "./radio-group-item";
import { useRadioGroupForm } from "./use-radio-group-form";
import {
  type RadioGroupActivationMode,
  type RadioGroupBoundaryDirection,
  type RadioGroupNavigationDirection,
  useRadioGroupNavigation,
} from "./use-radio-group-navigation";

export type {
  RadioGroupActivationMode,
  RadioGroupBoundaryDirection,
  RadioGroupNavigationDirection,
};

/** Props for radio group root. */
type RadioGroupRootProps = Omit<
  ComponentPropsWithRef<"div">,
  | "children"
  | "role"
  | "onChange"
  | "onKeyDown"
  | "className"
  | "ref"
  | "aria-label"
  | "aria-labelledby"
  | "aria-orientation"
  | "aria-required"
  | "aria-invalid"
  | "aria-disabled"
>;

/**
 * @typeParam TValue - Convenience assertion for the value union surfaced through
 * `value`/`onChange`/`onNavigate`/`onEnter`. Values originate from the rendered
 * items' `data-value` strings and are asserted to `TValue`, not validated; in
 * development an unregistered value warns (see `warnUnregisteredValue`).
 */
export interface RadioGroupProps<TValue extends string = string> extends RadioGroupRootProps {
  /** Controlled selected value. */
  value?: TValue;
  /** Initial selected value for uncontrolled usage. */
  defaultValue?: TValue;
  /** Called when the selected value changes. */
  onChange?: (value: TValue) => void;
  /** Called when arrow, Home, or End navigation moves to an item. */
  onNavigate?: (value: TValue, direction: RadioGroupNavigationDirection) => void;
  /** Called when Enter commits the focused item. */
  onEnter?: (value: TValue, event: ReactKeyboardEvent<HTMLDivElement>) => void;
  /** Called when keyboard navigation highlights a new item or clears highlight. */
  onHighlightChange?: (value: TValue | null) => void;
  /** Called before the built-in group key handling; call event.preventDefault() to suppress it. */
  onKeyDown?: (event: ReactKeyboardEvent) => void;
  /** Controlled highlighted item value for keyboard navigation. */
  highlighted?: TValue | null;
  /** Layout orientation. All four arrow keys still navigate per APG radio behavior. */
  orientation?: "vertical" | "horizontal";
  /** Whether arrow-key navigation wraps at the first and last item. */
  wrap?: boolean;
  /** Enable built-in arrow-key navigation. */
  keyboardNavigation?: boolean;
  /**
   * Automatic selects on arrow navigation; manual moves focus/highlight until Space or Enter
   * commits.
   */
  activationMode?: RadioGroupActivationMode;
  /** Called when non-wrapping navigation reaches the first or last item. */
  onNavigationBoundaryReached?: (
    direction: RadioGroupBoundaryDirection,
    event: globalThis.KeyboardEvent,
    key: string,
  ) => void;
  /** Disables the custom control and hidden input. */
  disabled?: boolean;
  /** Focuses the highlighted, selected, or first enabled item when the group becomes active. */
  autoFocus?: boolean;
  /** Selectable control size token. */
  size?: RadioSize;
  /** Indicator style. */
  variant?: SelectableVariant;
  /** Shared hidden native input name for grouped form submission. */
  name?: string;
  /** Requires one enabled item to be selected. */
  required?: boolean;
  /** Visible group label. */
  label?: string;
  /** Accessible name for the radiogroup. Overrides the visible label when supplied. */
  "aria-label"?: string;
  /** ID of the element that labels this component. */
  "aria-labelledby"?: string;
  /** ARIA invalid state forwarded to the rendered control. */
  "aria-invalid"?: AriaAttributes["aria-invalid"];
  /** Additional class names merged onto the rendered element. */
  className?: string;
  /** Content rendered inside the component. */
  children: ReactNode;
  /** Ref forwarded to the underlying element. */
  ref?: Ref<HTMLDivElement>;
}

function collectEnabledDirectRadioValues(children: ReactNode): string[] {
  return Children.toArray(children).flatMap((child) => {
    if (!isValidElement<RadioGroupItemProps>(child) || child.type !== RadioGroupItem) return [];
    const props = child.props;
    if (
      props.disabled ||
      props.hidden ||
      props.inert ||
      props["aria-hidden"] === true ||
      props["aria-hidden"] === "true"
    ) {
      return [];
    }
    return [props.value];
  });
}

/** Group root with context, selection state, and keyboard navigation. */
export function RadioGroup<TValue extends string = string>(props: RadioGroupProps<TValue>) {
  const {
    value: controlledValue,
    defaultValue,
    onChange,
    onNavigate,
    onEnter,
    onHighlightChange,
    onKeyDown,
    highlighted: controlledHighlighted,
    orientation = "vertical",
    wrap = true,
    keyboardNavigation = true,
    activationMode = "automatic",
    onNavigationBoundaryReached,
    disabled = false,
    autoFocus = false,
    size = "md",
    variant = "bullet",
    name,
    required,
    label,
    "aria-label": ariaLabel,
    "aria-labelledby": ariaLabelledBy,
    "aria-invalid": ariaInvalid,
    className,
    children,
    ref,
    ...rootProps
  } = props;
  const containerRef = useRef<HTMLDivElement>(null);
  const composedRef = useComposedRefs(containerRef, ref);
  const generatedId = useId();
  const labelId = `${generatedId}-label`;
  const hasAutoFocusedRef = useRef(false);
  const fieldsetDisabled = useFieldsetDisabled(containerRef);
  const isDisabled = disabled || fieldsetDisabled;
  const { items, registerItem, unregisterItem } = useSelectableCollection(containerRef);
  const [hasLiveRegistrations, setHasLiveRegistrations] = useState(false);

  const registerLiveItem = useCallback(
    (itemId: string, itemValue: string, itemDisabled: boolean, element: HTMLElement | null) => {
      setHasLiveRegistrations(true);
      registerItem(itemId, itemValue, itemDisabled, element);
    },
    [registerItem],
  );

  // Public props narrow on TValue; internal state stays string-typed because the
  // selectable-collection layer keys items by data-value strings.
  const [value, setValue, , resetValue] = useControllableState<string | undefined>({
    value: controlledValue,
    controlled: "value" in props,
    defaultValue,
    onChange: (next) => {
      if (next === undefined) return;
      warnUnregisteredValue(
        "RadioGroup",
        next,
        items.map((item) => item.value),
      );
      onChange?.(next as TValue);
    },
  });
  const [highlightedValue, setHighlightedValue] = useControllableState<string | null>({
    value: controlledHighlighted,
    controlled: "highlighted" in props,
    defaultValue: null,
    onChange: onHighlightChange as ((value: string | null) => void) | undefined,
  });

  const enabledItems = getEnabledSelectableCollectionItems(items, isDisabled);
  const seededEnabledValues = isDisabled ? [] : collectEnabledDirectRadioValues(children);
  const enabledValues = hasLiveRegistrations
    ? enabledItems.map((item) => item.value)
    : seededEnabledValues;
  const validHighlightedValue =
    highlightedValue !== null && enabledValues.includes(highlightedValue) ? highlightedValue : null;
  const validSelectedValue = value !== undefined && enabledValues.includes(value) ? value : null;
  const isValueControlled = "value" in props;

  const {
    effectiveRequired,
    requiredInvalid,
    validationInputRef,
    invalidatePendingReset,
    handleValueChange,
    handleRequiredInvalid,
    setRequiredInvalid,
  } = useRadioGroupForm({
    containerRef,
    value,
    defaultValue,
    enabledValues,
    required,
    isValueControlled,
    validSelectedValue,
    resetValue,
    setValue,
  });

  const resolvedAriaLabelledBy = ariaLabel
    ? undefined
    : mergeIds(ariaLabelledBy, label ? labelId : undefined);

  const { tabTargetValue, handleKeyDown } = useRadioGroupNavigation<TValue>({
    containerRef,
    items,
    value,
    highlightedValue,
    enabledValues,
    activationMode,
    keyboardNavigation,
    isDisabled,
    wrap,
    onNavigationBoundaryReached,
    onNavigate,
    onEnter,
    onKeyDown,
    setHighlightedValue,
    invalidatePendingReset,
    setRequiredInvalid,
    setValue,
    handleValueChange,
  });

  useEffect(() => {
    if (!autoFocus || !keyboardNavigation || isDisabled) {
      hasAutoFocusedRef.current = false;
      return;
    }
    if (hasAutoFocusedRef.current) return;

    const activeItems = getEnabledSelectableCollectionItems(items, isDisabled);
    const target = resolveSelectableCollectionItem(activeItems, highlightedValue, value);
    if (!target?.element) return;

    target.element.focus();
    setHighlightedValue(target.value);
    hasAutoFocusedRef.current = true;
  }, [
    autoFocus,
    keyboardNavigation,
    isDisabled,
    items,
    highlightedValue,
    value,
    setHighlightedValue,
  ]);

  const contextValue: RadioGroupContextValue = useMemo(
    () => ({
      value,
      onChange: handleValueChange,
      registerItem: registerLiveItem,
      unregisterItem,
      disabled: isDisabled,
      keyboardNavigation,
      size,
      variant,
      highlightedValue: validHighlightedValue,
      name,
      required: effectiveRequired,
      onRequiredInvalid: handleRequiredInvalid,
      tabTargetValue,
    }),
    [
      value,
      handleValueChange,
      registerLiveItem,
      unregisterItem,
      isDisabled,
      keyboardNavigation,
      size,
      variant,
      validHighlightedValue,
      name,
      effectiveRequired,
      handleRequiredInvalid,
      tabTargetValue,
    ],
  );

  return (
    <RadioGroupContext value={contextValue}>
      {label && (
        <div
          id={labelId}
          data-slot="radio-group-label"
          className={cn(
            "mb-2 font-mono font-bold text-muted-foreground",
            selectableLabelVariants({ size }),
          )}
        >
          {label}
        </div>
      )}
      {effectiveRequired && !name && (
        <input
          ref={validationInputRef}
          type="checkbox"
          data-slot="radio-group-validation"
          required
          checked={validSelectedValue !== null}
          disabled={isDisabled}
          tabIndex={-1}
          aria-hidden={true}
          className="sr-only"
          onChange={() => {}}
          onInvalid={(event) => {
            event.preventDefault();
            handleRequiredInvalid();
            enabledItems[0]?.element?.focus();
          }}
        />
      )}
      <div
        {...rootProps}
        ref={composedRef}
        role="radiogroup"
        data-slot="radio-group"
        data-diffgazer-selectable-owner="radio"
        aria-label={ariaLabel}
        aria-labelledby={resolvedAriaLabelledBy}
        aria-orientation={orientation}
        aria-required={effectiveRequired || undefined}
        aria-invalid={resolveAriaInvalid(
          ariaInvalid,
          effectiveRequired && requiredInvalid && validSelectedValue === null,
        )}
        aria-disabled={isDisabled || undefined}
        className={cn(
          "flex",
          orientation === "vertical" ? "flex-col gap-2" : "flex-row gap-4",
          className,
        )}
        onKeyDown={handleKeyDown}
      >
        {children}
      </div>
    </RadioGroupContext>
  );
}

"use client";

import {
  type AriaAttributes,
  type ComponentPropsWithRef,
  type KeyboardEvent as ReactKeyboardEvent,
  type MouseEvent as ReactMouseEvent,
  type ReactNode,
  type Ref,
  useCallback,
  useEffect,
  useId,
  useRef,
  useState,
} from "react";
import { useComposedRefs } from "@/hooks/use-composed-refs";
import { useControllableState } from "@/hooks/use-controllable-state";
import { useFormReset } from "@/hooks/use-form-reset";
import { mergeIds, resolveAriaInvalid } from "@/lib/aria";
import { useFieldsetDisabled } from "@/lib/fieldset-disabled";
import {
  type SelectableSize,
  type SelectableVariant,
  selectableContainerClass,
  selectableDescriptionVariants,
  selectableIndicators,
  selectableIndicatorVariants,
  selectableLabelVariants,
  selectableVariants,
} from "@/lib/selectable-variants";
import { cn } from "@/lib/utils";

/** Allowed radio size values. */
export type RadioSize = SelectableSize;

const RADIO_CHECK_EVENT = "diffgazer:radio-check";

interface RadioCheckEventDetail {
  name: string;
  form: HTMLFormElement | null;
  root: Node;
  source: HTMLElement;
}

function dispatchRadioCheck(source: HTMLElement, name: string) {
  source.ownerDocument.dispatchEvent(
    new CustomEvent<RadioCheckEventDetail>(RADIO_CHECK_EVENT, {
      detail: {
        name,
        form: source.closest("form"),
        root: source.getRootNode(),
        source,
      },
    }),
  );
}

/** Props for radio root. */
type RadioRootProps = Omit<
  ComponentPropsWithRef<"div">,
  | "children"
  | "role"
  | "aria-checked"
  | "aria-disabled"
  | "aria-invalid"
  | "aria-label"
  | "aria-labelledby"
  | "aria-describedby"
  | "tabIndex"
  | "onChange"
  | "className"
  | "ref"
  | "data-value"
>;

/** Props for radio. */
export interface RadioProps extends RadioRootProps {
  /** Controlled checked state. */
  checked?: boolean;
  /** Initial checked state for uncontrolled usage. */
  defaultChecked?: boolean;
  /** Whether radio is tab target. */
  isTabTarget?: boolean;
  /** Called when the boolean checked state changes. */
  onChange?: (checked: boolean) => void;
  /** Visible label associated with the custom radio. */
  label?: ReactNode;
  /** Visible description wired with aria-describedby. */
  description?: ReactNode;
  /** Disables the custom control and hidden input. */
  disabled?: boolean;
  /** Marks the item as highlighted by a parent collection. */
  highlighted?: boolean;
  /** Selectable control size token. */
  size?: RadioSize;
  /** Hidden native input name used for same-name radio behavior and form submission. */
  name?: string;
  /** Hidden native input value used for form submission. */
  value?: string;
  /** Marks the hidden native radio input as required. */
  required?: boolean;
  /** Indicator style. */
  variant?: SelectableVariant;
  /** Accessible name when no visible label is supplied. */
  "aria-label"?: string;
  /** ID of the element that labels this component. */
  "aria-labelledby"?: string;
  /** ID of the element that describes this component. */
  "aria-describedby"?: string;
  /** ARIA invalid state forwarded to the rendered control. */
  "aria-invalid"?: AriaAttributes["aria-invalid"];
  /** Called when native invalid occurs. */
  onNativeInvalid?: () => void;
  /** Additional class names merged onto the rendered element. */
  className?: string;
  /** Ref forwarded to the underlying element. */
  ref?: Ref<HTMLDivElement>;
  /** Value exposed as a data attribute for styling and selectors. */
  "data-value"?: string;
}

/**
 * Standalone radio button. Same-name standalone radios stay mutually exclusive
 * via a document-level CustomEvent, but they are form-submission-only: they have
 * no arrow-key navigation and each is its own tab stop. For a keyboard-complete
 * group (roving focus, arrow navigation, single tab stop) use RadioGroup.
 */
export function Radio({
  checked,
  defaultChecked = false,
  isTabTarget = true,
  onChange,
  onClick,
  onKeyDown,
  onMouseEnter,
  label,
  description,
  disabled = false,
  highlighted = false,
  size = "md",
  variant = "bullet",
  name,
  value = "on",
  required,
  "aria-label": ariaLabel,
  "aria-labelledby": ariaLabelledBy,
  "aria-describedby": ariaDescribedBy,
  "aria-invalid": ariaInvalid,
  onNativeInvalid,
  className,
  ref,
  "data-value": dataValue,
  ...rootProps
}: RadioProps) {
  const generatedId = useId();
  const labelId = `${generatedId}-label`;
  const descriptionId = `${generatedId}-desc`;

  const rootRef = useRef<HTMLDivElement>(null);
  const nativeInputRef = useRef<HTMLInputElement>(null);
  const composedRef = useComposedRefs(rootRef, ref);
  const [isChecked, setIsChecked, , resetChecked] = useControllableState<boolean>({
    value: checked,
    defaultValue: defaultChecked,
    onChange,
  });
  const fieldsetDisabled = useFieldsetDisabled(rootRef);
  const isDisabled = disabled || fieldsetDisabled;
  const [nativeInvalid, setNativeInvalid] = useState(false);
  const resolvedAriaInvalid = resolveAriaInvalid(
    ariaInvalid,
    nativeInvalid && required && !isChecked,
  );
  const resolvedAriaLabelledBy = ariaLabel
    ? undefined
    : mergeIds(ariaLabelledBy, label ? labelId : undefined);
  const resolvedAriaDescribedBy = mergeIds(
    ariaDescribedBy,
    description ? descriptionId : undefined,
  );
  const controlledFormReset =
    checked === undefined
      ? undefined
      : {
          syncResetBaseline: () => {
            if (rootRef.current?.hasAttribute("data-diffgazer-radio-group-item")) return;
            if (nativeInputRef.current) nativeInputRef.current.defaultChecked = isChecked;
          },
          onReset: () => {
            if (rootRef.current?.hasAttribute("data-diffgazer-radio-group-item")) return;
            setNativeInvalid(false);
          },
        };

  const invalidatePendingReset = useFormReset(
    rootRef,
    defaultChecked,
    (value) => {
      setNativeInvalid(false);
      resetChecked(value);
    },
    checked === undefined,
    controlledFormReset,
  );

  const notifySameNameRadios = useCallback(() => {
    if (!name || !rootRef.current) return;
    dispatchRadioCheck(rootRef.current, name);
  }, [name]);

  useEffect(() => {
    if (!name || rootRef.current?.hasAttribute("data-diffgazer-radio-group-item")) return;

    const ownerDocument = rootRef.current?.ownerDocument;
    if (!ownerDocument) return;

    const handleRadioCheck = (event: Event) => {
      const detail = (event as CustomEvent<Partial<RadioCheckEventDetail> | undefined>).detail;
      if (
        !detail ||
        detail.name !== name ||
        detail.source === rootRef.current ||
        detail.form !== (rootRef.current?.closest("form") ?? null) ||
        detail.root !== rootRef.current?.getRootNode()
      ) {
        return;
      }

      invalidatePendingReset();
      setIsChecked(false);
    };

    ownerDocument.addEventListener(RADIO_CHECK_EVENT, handleRadioCheck);
    return () => ownerDocument.removeEventListener(RADIO_CHECK_EVENT, handleRadioCheck);
  }, [invalidatePendingReset, name, setIsChecked]);

  useEffect(() => {
    if (isChecked) notifySameNameRadios();
  }, [isChecked, notifySameNameRadios]);

  const toggle = () => {
    if (isDisabled) return;
    invalidatePendingReset();
    setNativeInvalid(false);
    setIsChecked(true);
  };

  const handleClick = (event: ReactMouseEvent<HTMLDivElement>) => {
    if (isDisabled) {
      event.preventDefault();
      return;
    }
    onClick?.(event);
    if (!event.defaultPrevented) toggle();
  };

  const handleKeyDown = (e: ReactKeyboardEvent<HTMLDivElement>) => {
    if (isDisabled) return;
    onKeyDown?.(e);
    if (e.defaultPrevented) return;
    if (e.key === " ") {
      e.preventDefault();
      toggle();
    }
  };

  return (
    <>
      {(name || required) && (
        <input
          ref={nativeInputRef}
          type="radio"
          data-slot="radio-form-mirror"
          name={name}
          value={value}
          checked={isChecked}
          required={required}
          disabled={isDisabled}
          className="sr-only"
          tabIndex={-1}
          aria-hidden={true}
          onChange={() => {}}
          onInvalid={(event) => {
            event.preventDefault();
            onNativeInvalid?.();
            if (!onNativeInvalid) setNativeInvalid(true);
            const group = rootRef.current?.closest('[role="radiogroup"]');
            const owner = group?.querySelector<HTMLElement>(
              '[role="radio"]:not([aria-disabled="true"])',
            );
            (owner ?? rootRef.current)?.focus();
          }}
        />
      )}
      {/* biome-ignore lint/a11y/useSemanticElements: this is the custom-styled radio control; a hidden native <input type="radio"> (rendered separately) owns form submission, so the visible control uses role="radio". */}
      <div
        {...rootProps}
        ref={composedRef}
        role="radio"
        data-slot="radio"
        data-value={dataValue ?? value}
        data-state={isChecked ? "checked" : "unchecked"}
        data-disabled={isDisabled ? "" : undefined}
        data-highlighted={highlighted ? "" : undefined}
        aria-checked={isChecked}
        aria-disabled={isDisabled || undefined}
        aria-invalid={resolvedAriaInvalid}
        aria-label={ariaLabel}
        aria-labelledby={resolvedAriaLabelledBy}
        aria-describedby={resolvedAriaDescribedBy}
        tabIndex={!isDisabled && isTabTarget ? 0 : -1}
        onClick={handleClick}
        onKeyDown={handleKeyDown}
        onMouseEnter={onMouseEnter}
        className={cn(
          selectableVariants({ highlighted, disabled: isDisabled }),
          selectableContainerClass,
          description && "items-start",
          className,
        )}
      >
        <span
          aria-hidden="true"
          className={selectableIndicatorVariants({
            size,
            checked: isChecked,
            highlighted,
          })}
        >
          {selectableIndicators[variant][isChecked ? "checked" : "unchecked"]}
        </span>
        {label && (
          <div className={cn("flex flex-col min-w-0", !description && "justify-center")}>
            <span id={labelId} className={selectableLabelVariants({ size })}>
              {label}
            </span>
            {description && (
              <span id={descriptionId} className={selectableDescriptionVariants({ highlighted })}>
                {description}
              </span>
            )}
          </div>
        )}
      </div>
    </>
  );
}

"use client";

import { type ReactNode, useId, useLayoutEffect, useRef } from "react";
import { useComposedRefs } from "@/hooks/use-composed-refs";
import { Radio, type RadioProps } from "./radio";
import { useRadioGroupContext } from "./radio-group-context";

/** Props for radio group item. */
export interface RadioGroupItemProps<TValue extends string = string>
  extends Omit<
    RadioProps,
    | "checked"
    | "defaultChecked"
    | "isTabTarget"
    | "onChange"
    | "highlighted"
    | "size"
    | "variant"
    | "name"
    | "required"
    | "onNativeInvalid"
    | "value"
    | "data-value"
  > {
  /** Item value. Must be unique within the group. */
  value: TValue;
  /** Visible item label. */
  label: ReactNode;
  /** Visible item description wired with aria-describedby. */
  description?: ReactNode;
  /** Disables the item. */
  disabled?: boolean;
}

/** Radio item composed inside RadioGroup. */
export function RadioGroupItem<TValue extends string = string>({
  value,
  label,
  description,
  disabled: itemDisabled,
  ref,
  ...radioProps
}: RadioGroupItemProps<TValue>) {
  const context = useRadioGroupContext();
  const itemId = useId();
  const rootRef = useRef<HTMLDivElement>(null);
  const composedRef = useComposedRefs(rootRef, ref);
  const isSelected = context.value === value;
  const isDisabled = context.disabled || !!itemDisabled;
  const isHighlighted = context.highlightedValue === value;
  const isTabTarget =
    !isDisabled && (!context.keyboardNavigation || context.tabTargetValue === value);
  const { registerItem, unregisterItem } = context;

  useLayoutEffect(() => {
    registerItem(itemId, value, isDisabled, rootRef.current);
    return () => unregisterItem(itemId);
  }, [registerItem, unregisterItem, itemId, value, isDisabled]);

  return (
    <Radio
      {...radioProps}
      ref={composedRef}
      data-diffgazer-radio-group-item=""
      data-value={value}
      value={value}
      checked={isSelected}
      isTabTarget={isTabTarget}
      onChange={() => context.onChange(value)}
      label={label}
      description={description}
      disabled={isDisabled}
      highlighted={isHighlighted}
      size={context.size}
      variant={context.variant}
      name={context.name}
      required={context.name ? context.required : undefined}
      onNativeInvalid={context.onRequiredInvalid}
    />
  );
}

"use client";

import { createContext, useContext } from "react";
import type { SelectableVariant } from "@/lib/selectable-variants";
import type { RadioSize } from "./radio";

/** Context value shared by radio group. */
export interface RadioGroupContextValue {
  /** Controlled selected value. */
  value?: string;
  /** Called when the selected value changes. */
  onChange: (value: string) => void;
  /** Registers item with radio group. */
  registerItem: (
    itemId: string,
    itemValue: string,
    disabled: boolean,
    element: HTMLElement | null,
  ) => void;
  /** Unregisters item from radio group. */
  unregisterItem: (itemId: string) => void;
  /** Disables the custom control and hidden input. */
  disabled: boolean;
  /** Enable built-in arrow-key navigation. */
  keyboardNavigation: boolean;
  /** Selectable control size token. */
  size: RadioSize;
  /** Indicator style. */
  variant: SelectableVariant;
  highlightedValue: string | null;
  /** Shared hidden native input name for grouped form submission. */
  name?: string;
  /** Requires one enabled item to be selected. */
  required?: boolean;
  /** Called when required invalid occurs. */
  onRequiredInvalid: () => void;
  tabTargetValue: string | null;
}

/** React context backing radio group. */
export const RadioGroupContext = createContext<RadioGroupContextValue | undefined>(undefined);

/** Reads the radio group context. */
export function useRadioGroupContext() {
  const context = useContext(RadioGroupContext);
  if (!context) {
    throw new Error("RadioGroupItem must be used within RadioGroup");
  }
  return context;
}

"use client";

import { type RefObject, useCallback, useRef, useState } from "react";
import { useFormReset } from "@/hooks/use-form-reset";

export interface UseRadioGroupFormOptions {
  containerRef: RefObject<HTMLDivElement | null>;
  value: string | undefined;
  defaultValue: string | undefined;
  enabledValues: string[];
  required: boolean | undefined;
  isValueControlled: boolean;
  validSelectedValue: string | null;
  resetValue: (value: string | undefined) => void;
  setValue: (next: string) => void;
}

/** Native form reset, required validity, and validation mirror for RadioGroup. */
export function useRadioGroupForm({
  containerRef,
  value,
  defaultValue,
  enabledValues,
  required,
  isValueControlled,
  validSelectedValue,
  resetValue,
  setValue,
}: UseRadioGroupFormOptions) {
  const validationInputRef = useRef<HTMLInputElement>(null);
  const [requiredInvalid, setRequiredInvalid] = useState(false);
  const effectiveRequired = !!required && enabledValues.length > 0;

  const controlledFormReset = isValueControlled
    ? {
        syncResetBaseline: () => {
          for (const input of containerRef.current?.querySelectorAll<HTMLInputElement>(
            'input[data-slot="radio-form-mirror"]',
          ) ?? []) {
            const item = input.nextElementSibling;
            if (!item?.hasAttribute("data-diffgazer-radio-group-item")) continue;
            if (item.closest('[data-slot="radio-group"]') !== containerRef.current) continue;
            input.defaultChecked = input.value === value;
          }
          const validation = validationInputRef.current;
          if (validation) validation.defaultChecked = validSelectedValue !== null;
        },
        onReset: () => setRequiredInvalid(false),
      }
    : undefined;

  const invalidatePendingReset = useFormReset(
    containerRef,
    defaultValue,
    (nextValue) => {
      setRequiredInvalid(false);
      resetValue(nextValue);
    },
    !isValueControlled,
    controlledFormReset,
  );

  const handleValueChange = useCallback(
    (next: string) => {
      invalidatePendingReset();
      setRequiredInvalid(false);
      setValue(next);
    },
    [invalidatePendingReset, setValue],
  );

  const handleRequiredInvalid = useCallback(() => {
    setRequiredInvalid(true);
  }, []);

  return {
    effectiveRequired,
    requiredInvalid,
    validationInputRef,
    invalidatePendingReset,
    handleValueChange,
    handleRequiredInvalid,
    setRequiredInvalid,
  };
}

"use client";

import { type KeyboardEvent as ReactKeyboardEvent, type RefObject, useRef } from "react";
import { useNavigation } from "@/hooks/use-navigation";
import { isHTMLElementForContainer } from "@/lib/aria";
import { warnUnregisteredValue } from "@/lib/warn-unregistered-value";

/** Whether arrow navigation immediately selects or only highlights until commit. */
export type RadioGroupActivationMode = "automatic" | "manual";
/** Boundary reached by non-wrapping radio navigation. */
export type RadioGroupBoundaryDirection = "previous" | "next";
/** Direction emitted by radiogroup navigation callbacks. */
export type RadioGroupNavigationDirection = "previous" | "next" | "first" | "last";

const RADIO_PREVIOUS_KEYS = ["ArrowUp", "ArrowLeft"] as const;
const RADIO_NEXT_KEYS = ["ArrowDown", "ArrowRight"] as const;

function getRadioNavigationDirection(key: string): RadioGroupNavigationDirection | null {
  if (key === "ArrowUp" || key === "ArrowLeft") return "previous";
  if (key === "ArrowDown" || key === "ArrowRight") return "next";
  if (key === "Home") return "first";
  if (key === "End") return "last";
  return null;
}

interface SelectableCollectionItem {
  value: string;
}

export interface UseRadioGroupNavigationOptions<TValue extends string = string> {
  containerRef: RefObject<HTMLDivElement | null>;
  items: SelectableCollectionItem[];
  value: string | undefined;
  highlightedValue: string | null;
  enabledValues: string[];
  activationMode: RadioGroupActivationMode;
  keyboardNavigation: boolean;
  isDisabled: boolean;
  wrap: boolean;
  onNavigationBoundaryReached?: (
    direction: RadioGroupBoundaryDirection,
    event: globalThis.KeyboardEvent,
    key: string,
  ) => void;
  onNavigate?: (value: TValue, direction: RadioGroupNavigationDirection) => void;
  onEnter?: (value: TValue, event: ReactKeyboardEvent<HTMLDivElement>) => void;
  onKeyDown?: (event: ReactKeyboardEvent) => void;
  setHighlightedValue: (next: string | null) => void;
  invalidatePendingReset: () => void;
  setRequiredInvalid: (invalid: boolean) => void;
  setValue: (next: string) => void;
  handleValueChange: (next: string) => void;
}

/** APG keyboard navigation, activation mode, and tab-target derivation for RadioGroup. */
export function useRadioGroupNavigation<TValue extends string = string>({
  containerRef,
  items,
  value,
  highlightedValue,
  enabledValues,
  activationMode,
  keyboardNavigation,
  isDisabled,
  wrap,
  onNavigationBoundaryReached,
  onNavigate,
  onEnter,
  onKeyDown,
  setHighlightedValue,
  invalidatePendingReset,
  setRequiredInvalid,
  setValue,
  handleValueChange,
}: UseRadioGroupNavigationOptions<TValue>) {
  const navigationEventRef = useRef<ReactKeyboardEvent<HTMLDivElement> | null>(null);

  const preferredTabValues =
    activationMode === "manual" ? [highlightedValue, value] : [value, highlightedValue];
  const tabTargetValue =
    preferredTabValues.find(
      (candidate): candidate is string =>
        candidate !== null && candidate !== undefined && enabledValues.includes(candidate),
    ) ??
    enabledValues[0] ??
    null;

  const handleNavigatedItem = (next: string | null) => {
    if (next === null) return;
    setHighlightedValue(next);
    setRequiredInvalid(false);

    const direction = getRadioNavigationDirection(navigationEventRef.current?.key ?? "");
    if (direction !== null) {
      warnUnregisteredValue(
        "RadioGroup",
        next,
        items.map((item) => item.value),
      );
      onNavigate?.(next as TValue, direction);
    }

    if (activationMode === "automatic") {
      invalidatePendingReset();
      setValue(next);
    }
  };

  const handleNavigationEnter = (next: string) => {
    const event = navigationEventRef.current;
    if (!event) return;

    setHighlightedValue(next);
    handleValueChange(next);
    warnUnregisteredValue(
      "RadioGroup",
      next,
      items.map((item) => item.value),
    );
    onEnter?.(next as TValue, event);
  };

  const { onKeyDown: navKeyDown } = useNavigation({
    containerRef,
    role: "radio",
    highlighted: tabTargetValue,
    onHighlightChange: handleNavigatedItem,
    onEnter: handleNavigationEnter,
    wrap,
    enabled: keyboardNavigation && !isDisabled,
    moveFocus: true,
    scopeToContainer: true,
    upKeys: RADIO_PREVIOUS_KEYS,
    downKeys: RADIO_NEXT_KEYS,
    onNavigationBoundaryReached,
  });

  const handleKeyDown = (event: ReactKeyboardEvent<HTMLDivElement>) => {
    const eventTarget = isHTMLElementForContainer(event.target, containerRef.current)
      ? event.target
      : null;
    if (eventTarget && eventTarget.closest('[role="radiogroup"]') !== containerRef.current) {
      return;
    }

    onKeyDown?.(event);
    if (event.defaultPrevented || !keyboardNavigation || isDisabled) return;

    navigationEventRef.current = event;
    try {
      navKeyDown(event);
    } finally {
      navigationEventRef.current = null;
    }
  };

  return {
    tabTargetValue,
    handleKeyDown,
  };
}
